class Solution:
    def assignEdgeWeights(self, edges):
        MOD = 10**9 + 7
        from collections import defaultdict, deque
        g = defaultdict(list)
        for u, v in edges:
            g[u].append(v)
            g[v].append(u)
        depth = {1: 0}
        dq = deque([1])
        best = 0
        while dq:
            x = dq.popleft()
            for y in g[x]:
                if y not in depth:
                    depth[y] = depth[x] + 1
                    best = max(best, depth[y])
                    dq.append(y)
        ways = 0
        for mask in range(1 << best):
            ones = bin(mask).count('1')
            if ones % 2 == 1:
                ways += 1
        return ways % MOD

