        g = defaultdict(list)
        for u, v in edges:
            g[u].append(v)
            g[v].append(u)
        depth = {1: 0}
        dq = deque([1])
        best = 0
        while dq:
            x = dq.popleft()
            for y in g[x]:
                if y not in depth:
                    depth[y] = depth[x] + 1
                    if depth[y] > best:
                        best = depth[y]
                    dq.append(y)
        return pow(2, best - 1, MOD)

