var assignEdgeWeights = function(edges) {
    const MOD = 1000000007n;
    const g = new Map();
    const add = (a, b) => { if (!g.has(a)) g.set(a, []); g.get(a).push(b); };
    for (const [u, v] of edges) { add(u, v); add(v, u); }
    const depth = new Map([[1, 0]]);
    const dq = [1];
    let head = 0, best = 0;
    while (head < dq.length) {
        const x = dq[head++];
        for (const y of (g.get(x) || [])) {
            if (!depth.has(y)) {
                const d = depth.get(x) + 1;
                depth.set(y, d);
                if (d > best) best = d;
                dq.push(y);
            }
        }
    }
    let r = 1n;
    for (let i = 0; i < best - 1; i++) r = (r * 2n) % MOD;
    return Number(r);
};
